CREATE VIEW `dwd_advertisement_toponfullreport_view` (`id` COMMENT "主键id", `date` COMMENT "日期", `app_id` COMMENT "应用程序", `placement_id` COMMENT "广告位信息，group_by有选placement维度时才返回", `ad_format` COMMENT "广告样式，group_by有选adformat维度时才有返回，枚举值：rewarded video、interstitial、banner、native、splash", `revenue` COMMENT "收益", `ecpm` COMMENT "topon通过报表api向广告平台拉取到的实际收益和展示api计算出ecpm api，计算公式：（收益/展示api）*1000。注：ecpm api延迟1天提供", `request` COMMENT "三方广告平台的广告请求数", `fill_rate` COMMENT "匹配率（无匹配数，需基于请求数自行计算）", `impression` COMMENT "三方广告平台的展示数", `click` COMMENT "三方广告平台的点击数", `ctr` COMMENT "（三方广告平台的点击率）", `network_firm_id` COMMENT "广告平台id", `response` COMMENT "匹配数", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
COMMENT "阅读app内广告相关：TopOn广告聚合平台收益报表" AS SELECT `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`id`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`date`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`appid` AS `app_id`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`placementid` AS `placement_id`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`adformat` AS `ad_format`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`revenue`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`ecpm`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`request`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`fillrate` AS `fill_rate`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`impression`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`click`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`ctr`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`networkfirmid` AS `network_firm_id`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`Response`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`sr_createtime`, `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`.`sr_updatetime`
FROM `ods`.`ods_tidb_sharpengine_ads_global_TopOnFullReport`;
